mapper.select:
SELECT n.noticenum, n.projectid, n.subject, n.hitcount, n.isnotice, n.state, TO_CHAR(n.regdate, 'YYYY-MM-DD') AS regdate, TO_CHAR(n.updatedate, 'YYYY-MM-DD') AS updatedate, n.authorempid, e.name AS authorName FROM projectnotice n LEFT JOIN employee2 e ON n.authorempid = e.empId WHERE n.state = 1 AND n.projectid = #{projectid}
AND (n.subject LIKE '%' || #{keyword} || '%' OR n.content LIKE '%' || #{keyword} || '%')
ORDER BY n.isnotice DESC, n.noticenum DESC OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

mapper.insert:

    SELECT PROJECTNOTICEFILE_SEQ.NEXTVAL FROM dual

INSERT INTO projectnoticefile (
    filenum, savefilename, originalfilename, filesize, noticenum
) VALUES (
    #{filenum},
    #{savefilename},
    #{originalfilename, jdbcType=VARCHAR},
    #{filesize},
    #{noticenum}
)

mapper.select:
SELECT filenum, savefilename, originalfilename, filesize, noticenum
FROM projectnoticefile
WHERE filenum = #{filenum}
